                ThoughtSpot.RestApi.Sdk.Client.ApiClient              apiClient,
                System.Net.Http.HttpClient                    rawHttpClient,
                System.Net.Http.HttpClient?                   bareClient,
                System.Net.Http.SocketsHttpHandler?           bareHandler,
                ThoughtSpot.RestApi.Sdk.Client.IReadableConfiguration configuration,
                ThoughtSpot.RestApi.Sdk.ApiClientConfiguration        config,
                ThoughtSpot.RestApi.Sdk.Client.RefCountingHandler?    refCounter)
            {
                ApiClient     = apiClient;
                RawHttpClient = rawHttpClient;
                BareClient    = bareClient;
                BareHandler   = bareHandler;
                Configuration = configuration;
                Config        = config;
                RefCounter    = refCounter;
            }

            internal void Dispose()
            {
                ApiClient.Dispose();
                RawHttpClient.Dispose();
                BareClient?.Dispose();
