        /// </summary>
        /// <remarks>This is the required entry point when streaming methods (XxxStreamAsync) are needed — direct constructor use leaves streaming unavailable.</remarks>
        /// <param name="config">Connection settings including host, credentials, and SSL options.</param>
        /// <param name="cancellationToken">Optional cancellation token.</param>
        public static async System.Threading.Tasks.Task<SchedulesApi> CreateAsync(
            ThoughtSpot.RestApi.Sdk.ApiClientConfiguration config,
            System.Threading.CancellationToken cancellationToken = default)
        {
            var built = await BuildFromConfigAsync(config, cancellationToken).ConfigureAwait(false);
            var instance = new SchedulesApi(createAsyncSentinel: true);
            var apiClient = new ThoughtSpot.RestApi.Sdk.Client.ApiClient(built.HttpClient, built.Cfg.BasePath, null);
            apiClient.RetryPipeline = config.EnableRetries ? config.RetryPipeline : Polly.ResiliencePipeline<System.Net.Http.HttpResponseMessage>.Empty;
            instance._state = new ApiState(apiClient, built.HttpClient, built.BareClient, built.BareHandler, built.Cfg, config, built.RefCounter);
            return instance;
        }

        /// <summary>
        /// Applies a new <see cref="ThoughtSpot.RestApi.Sdk.ApiClientConfiguration"/> to this instance, replacing the
        /// host, credentials, SSL settings, timeout, and default headers in one atomic step.
        /// All existing HTTP clients and handlers are disposed and rebuilt from the new config.
        /// <para>
        /// Use the <c>with</c> expression on <see cref="Config"/> to change only specific fields:
        /// <code>await api.ApplyConfigurationAsync(api.Config with { Host = "https://new-host" });</code>
        /// </para>
        /// </summary>
        /// <param name="config">The new configuration to apply.</param>
        /// <param name="cancellationToken">Optional cancellation token.</param>
        public async System.Threading.Tasks.Task ApplyConfigurationAsync(
            ThoughtSpot.RestApi.Sdk.ApiClientConfiguration config,
            System.Threading.CancellationToken cancellationToken = default)
        {
            var built = await BuildFromConfigAsync(config, cancellationToken).ConfigureAwait(false);

            var newApiClient = new ThoughtSpot.RestApi.Sdk.Client.ApiClient(built.HttpClient, built.Cfg.BasePath, null);
            newApiClient.RetryPipeline = config.EnableRetries ? config.RetryPipeline : Polly.ResiliencePipeline<System.Net.Http.HttpResponseMessage>.Empty;
            var newState = new ApiState(newApiClient, built.HttpClient, built.BareClient, built.BareHandler, built.Cfg, config, built.RefCounter);

            // Atomic swap: after this line, all property reads on any thread see the new state.
            // No reader can ever observe a mix of old and new values.
#pragma warning disable CS0420 // passing volatile field to Interlocked is intentional — Interlocked is strictly stronger than volatile
            var oldState = System.Threading.Interlocked.Exchange(ref _state, newState);
#pragma warning restore CS0420

            if (oldState is not null)
            {
                // Defer disposal: wait until every in-flight request on the old stack finishes,
                // then dispose all old resources. This is fire-and-forget — the caller doesn't
                // need to wait for the old stack to drain.
                var drainTask = oldState.RefCounter is not null
                    ? oldState.RefCounter.ReleaseAsync()
                    : System.Threading.Tasks.Task.CompletedTask;
                _ = drainTask.ContinueWith(
                    _ => oldState.Dispose(),
                    System.Threading.Tasks.TaskContinuationOptions.None);
            }
        }

